    Var(String),
    If { cond: Box<Ast>, then: Box<Ast>, else_: Box<Ast> },
}

fn eval(ast: &Ast, env: &HashMap<String, i64>) -> i64 {
    match ast {
        Ast::Num(n) => *n,
        Ast::Var(name) => *env.get(name).unwrap_or(&0),
        Ast::Add(l, r) => eval(l, env) + eval(r, env),
        Ast::Mul(l, r) => eval(l, env) * eval(r, env),
        Ast::If { cond, then, else_ } =>
            if eval(cond, env) != 0 { eval(then, env) } else { eval(else_, env) },
        Ast::Let { name, value, body } => {
            let mut env2 = env.clone();
            env2.insert(name.clone(), eval(value, env));
            eval(body, &env2)
        }
    }
}

fn free_vars(ast: &Ast, bound: &HashSet<String>) -> HashSet<String> {
    match ast {
        Ast::Num(_) => HashSet::new(),
        Ast::Var(name) =>
            if bound.contains(name) { HashSet::new() } else { [name.clone()].into() },
        Ast::Add(l, r) | Ast::Mul(l, r) => {
            let mut v = free_vars(l, bound);
            v.extend(free_vars(r, bound));
            v
        }
        Ast::If { cond, then, else_ } => {
            let mut v = free_vars(cond, bound);
            v.extend(free_vars(then, bound));
            v.extend(free_vars(else_, bound));
            v
        }
        Ast::Let { name, value, body } => {
            let mut bound2 = bound.clone();
            bound2.insert(name.clone());
            let mut v = free_vars(value, bound);
            v.extend(free_vars(body, &bound2));
            v
        }
    }
}

