enum State { Idle, Running, Paused, Done }

#[derive(Debug)]
enum Event { Start, Pause, Resume, Stop, Reset }

fn transition(state: State, event: &Event) -> State {
    // Tuple pattern: (state, event) — each arm is a complete transition rule
    match (state, event) {
        (State::Idle,    Event::Start)  => State::Running,
        (State::Running, Event::Pause)  => State::Paused,
        (State::Running, Event::Stop)   => State::Done,
        (State::Paused,  Event::Resume) => State::Running,
        (State::Paused,  Event::Stop)   => State::Done,
        (State::Done,    Event::Reset)  => State::Idle,
        // All other (state, event) combinations: no transition
        (s, _) => s,
    }
}

fn is_valid_transition(state: State, event: &Event) -> bool {
    !matches!(
        (state, event),
        (State::Idle, Event::Start) |
        (State::Running, Event::Pause | Event::Stop) |
        (State::Paused, Event::Resume | Event::Stop) |
        (State::Done, Event::Reset)
    ) == false // valid iff matches one of the above
}

