#[derive(Debug)]
enum Route<'a> {
    Static(&'a str),
    Dynamic { prefix: &'a str, params: Vec<String> },
    NotFound,
}

fn handle(route: &Route<'_>) -> String {
    match route {
        // Match on specific static paths:
        Route::Static("/")      => String::from("homepage"),
        Route::Static("/about") => String::from("about page"),
        Route::Static(path)     => format!("static: {}", path),

        // Match on specific prefixes inside Dynamic:
        Route::Dynamic { prefix: "/api",   params } =>
            format!("API endpoint: {:?}", params),
        Route::Dynamic { prefix: "/admin", params } =>
            format!("Admin: {:?}", params),
        Route::Dynamic { prefix, params } =>
            format!("dynamic {}: {:?}", prefix, params),

        Route::NotFound => String::from("404"),
    }
}

fn is_api(route: &Route<'_>) -> bool {
    matches!(route,
        Route::Dynamic { prefix: "/api", .. } |
        Route::Static("/api")
    )
}

fn main() {
    let routes: Vec<Route<'_>> = vec![
        Route::Static("/"),
        Route::Static("/about"),
        Route::Static("/other"),
        Route::Dynamic { prefix: "/api",   params: vec![String::from("users")] },
        Route::Dynamic { prefix: "/admin", params: vec![String::from("panel")] },
        Route::NotFound,
    ];
    for r in &routes {
        println!("{:?}: {} api={}", r, handle(r), is_api(r));
    }
}

