// Combinator form — best for simple linear transformations:
fn parse_and_double_comb(input: Option<&str>) -> Result<i32, String> {
    input
        .ok_or_else(|| String::from("no input"))
        .and_then(|s| s.trim().parse::<i32>().map_err(|e| format!("parse: {}", e)))
        .and_then(|n| {
            if n < 0 { Err(format!("negative: {}", n)) }
            else     { Ok(n * 2) }
        })
}

// ? form — best when each step is already Result/Option:
fn parse_and_double_q(input: Option<&str>) -> Result<i32, String> {
    let s = input.ok_or_else(|| String::from("no input"))?;
    let n: i32 = s.trim().parse().map_err(|e: std::num::ParseIntError| e.to_string())?;
    if n < 0 { return Err(format!("negative: {}", n)); }
    Ok(n * 2)
}

// match form — best when each branch needs different complex logic:
fn parse_and_double_match(input: Option<&str>) -> Result<i32, String> {
    let s = match input {
        None => return Err(String::from("no input")),
        Some(s) => s.trim(),
    };
    match s.parse::<i32>() {
        Err(_) if s.is_empty() => Err(String::from("empty string")),
        Err(e)                 => Err(format!("parse: {}", e)),
        Ok(n) if n < 0         => Err(format!("negative: {}", n)),
        Ok(n)                  => Ok(n * 2),
    }
}

fn main() {
    for s in [Some("21"), Some("-5"), Some("bad"), None, Some("")] {
        println!("{:?}: comb={:?} q={:?} match={:?}",
            s,
            parse_and_double_comb(s),
            parse_and_double_q(s),
            parse_and_double_match(s));
    }
}
